"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[70759],{66493:e=>{e.exports=JSON.parse('{"tag":{"label":"teleport","permalink":"/dst-api-webdocs/docs/tags/teleport","allTagsPath":"/dst-api-webdocs/docs/tags","count":17,"items":[{"id":"game-scripts/components/blinkstaff","title":"Blinkstaff","description":"Handles teleportation logic and visual/audio effects for the Blink Staff item in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/blinkstaff"},{"id":"game-scripts/prefabs/bootleg","title":"Bootleg","description":"A throwable item that creates a two-way ocean whirl portal teleporter when tossed into ocean water.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bootleg"},{"id":"game-scripts/prefabs/hermitcrab_shell","title":"Hermitcrab Shell","description":"A consumable horn item that enables teleportation to the Hermit\'s house and has a secondary use for tending plants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrab_shell"},{"id":"game-scripts/prefabs/pocketwatch","title":"Pocketwatch","description":"Provides spell-casting functionality for pocketwatch items, enabling healing, resurrection, recall, and warp effects via shared core logic and component interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocketwatch"},{"id":"game-scripts/components/positionalwarp","title":"Positionalwarp","description":"Caches entity position history for rollback-style teleportation and manages visual position markers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/positionalwarp"},{"id":"game-scripts/components/remoteteleporter","title":"Remoteteleporter","description":"Handles remote teleportation logic by selecting a valid destination pad and moving the doer and nearby items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/remoteteleporter"},{"id":"game-scripts/prefabs/retrofit_fumaroleteleporter","title":"Retrofit Fumaroleteleporter","description":"Spawns a pair of linked wormholes to retrofit fumarole teleporter functionality in the game world, primarily for connecting cave zones via Tier4 tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/retrofit_fumaroleteleporter"},{"id":"game-scripts/components/teleportedoverride","title":"Teleportedoverride","description":"Stores custom destination functions for teleportation overrides on an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/teleportedoverride"},{"id":"game-scripts/components/teleporter","title":"Teleporter","description":"Manages inter- and intra-world teleportation of entities, including followers and items, with support for migration, camera transitions, and walkable offset alignment.","permalink":"/dst-api-webdocs/docs/game-scripts/components/teleporter"},{"id":"game-scripts/prefabs/tentacle_pillar_hole","title":"Tentacle Pillar Hole","description":"Serves as a static teleporter anchor that spawns a tentacle pillar when players or items interact with it, and handles associated sound effects, state synchronization, and residue behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tentacle_pillar_hole"},{"id":"game-scripts/prefabs/townportaltalisman","title":"Townportaltalisman","description":"Manages the behavior and animation of the Town Portal Talisman item, which links two portals for teleportation and updates state based on inventory and connection status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/townportaltalisman"},{"id":"game-scripts/prefabs/vault_lobby_exit","title":"Vault Lobby Exit","description":"A non-interactive exit point for teleportation from the Caves to the Vault Lobby, handling sound triggers and teleporter state management.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_lobby_exit"},{"id":"game-scripts/components/vaultroommanager","title":"Vaultroommanager","description":"Manages the layout, state, and teleportation logic for the Vault dungeon, including room connections, marker registration, player tracking, and randomization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vaultroommanager"},{"id":"game-scripts/prefabs/winona_telebrella","title":"Winona Telebrella","description":"A powered inventory item that enables long-range teleportation when charged, interacts with engineering circuits, and supports Winona skill enhancements.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_telebrella"},{"id":"game-scripts/components/winonateleportpadmanager","title":"Winonateleportpadmanager","description":"Tracks and manages all registered Winona teleport pads on the map for network synchronization and world-wide navigation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/winonateleportpadmanager"},{"id":"game-scripts/prefabs/wormhole","title":"Wormhole","description":"Manages the Wormhole prefab, a teleportation structure that opens when players approach and teleports entities (including followers) to a linked Teleporter.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormhole"},{"id":"game-scripts/prefabs/wortox_reviver","title":"Wortox Reviver","description":"Manages the Wortox player\'s life revival mechanic by storing and releasing souls, linked to skill tree progression and owner identity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox_reviver"}],"unlisted":false}}')}}]);